const now = new Date().toISOString().split('T')[0];
const time = new Date().toLocaleTimeString('en-AU', {timeZone: 'UTC'});

const anthropicStatus = $input.all()[0]?.json?.status?.description || 'Unknown';
const openaiStatus = $input.all()[1]?.json?.status?.description || 'Unknown';

const aiServices = [
  { name: 'Claude (Anthropic)', models: ['claude-opus-4-6', 'claude-sonnet-4-6', 'claude-haiku-4-5'], status: anthropicStatus, paid: true, tier: 'Premium' },
  { name: 'ChatGPT (OpenAI)', models: ['gpt-4o', 'o1', 'o3', 'o4-mini'], status: openaiStatus, paid: true, tier: 'Premium' },
  { name: 'Grok (xAI)', models: ['grok-3', 'grok-3-mini'], status: 'Operational', paid: true, tier: 'Premium' },
  { name: 'Gemini (Google)', models: ['gemini-2.0-flash', 'gemini-1.5-pro'], status: 'Operational', paid: false, tier: 'Free+Paid' },
  { name: 'Llama (Meta)', models: ['llama-4', 'llama-3.3'], status: 'Operational', paid: false, tier: 'Free/Open' },
  { name: 'Mistral', models: ['mistral-large-2', 'mistral-small'], status: 'Operational', paid: true, tier: 'Paid+Free' },
  { name: 'Perplexity', models: ['sonar-pro', 'sonar'], status: 'Operational', paid: true, tier: 'Paid+Free' },
  { name: 'Cohere', models: ['command-r-plus', 'command-r'], status: 'Operational', paid: true, tier: 'Paid+Free' },
  { name: 'Ollama (Local)', models: ['gemma4:e4b'], status: 'Operational', paid: false, tier: 'Free/Local' }
];

const statusEmoji = (s) => s === 'Operational' || s === 'All Systems Operational' ? '✅' : '⚠️';

const tableRows = aiServices.map(s => 
  `| ${statusEmoji(s.status)} **${s.name}** | ${s.models.join(', ')} | ${s.status} | ${s.tier} |`
).join('\n');

const mermaid = `\`\`\`mermaid
flowchart LR
    M[Mircea] --> GA[GA Supervisor]
    GA --> CL[Claude claude-opus-4-6]
    GA --> GPT[ChatGPT o1/o3/o4-mini]
    GA --> GR[Grok grok-3]
    GA --> GEM[Gemini 2.0]
    GA --> LL[Llama 4]
    GA --> MS[Mistral Large]
    GA --> PP[Perplexity Sonar]
    GA --> OL[Ollama Local]
    CL --> Best{Best for task}
    GPT --> Best
    GR --> Best
    GEM --> Best
    LL --> Best
    Best --> Result[Output to Mircea]
\`\`\``;

const report = `# AI Universe Daily Report — ${now}

**Generated:** ${time} UTC  
**Supervised by:** Grandfather's Axe (GA)  

## Live Status

| AI Service | Models | Status | Tier |
|-----------|--------|--------|------|
${tableRows}

## Architecture

${mermaid}

## Notes
- Check for new model releases at: anthropic.com/news, openai.com/blog, x.ai/blog
- Ollama running locally at: http://100.72.238.7:11434
- n8n API key: stored in /home/mircea/nemoclaw/bot.env

**Tag:** #ga #ai-supervisor #daily-report
`;

return [{ json: { report, date: now, filename: `AI_Daily_Report_${now}.md` } }];

